import scala.collection.mutable

def solve(n: Long, k: Long): Long = {
  if (k == 0) {
    if (n >= 1) 1 else 0
  } else {
    val dep = new Array[Int](61)
    dep(1) = 0
    for (s <- 2 to 60) {
      val pop = java.lang.Integer.bitCount(s)
      dep(s) = 1 + dep(pop)
    }
    val T = (1 to 60).filter(s => dep(s) == k - 1).toList
    if (T.isEmpty) {
      return 0
    }
    val bits = java.lang.Long.toBinaryString(n).toCharArray.map(c => if (c == '1') 1 else 0)
    val total_arr = computeCounts(bits)
    var result = 0L
    for (s_val <- T) {
      var cnt = 0L
      if (s_val < total_arr.length) {
        cnt = total_arr(s_val)
      }
      if (k == 1 && s_val == 1) {
        cnt -= 1
      }
      result += cnt
    }
    result
  }
}

def computeCounts(bits: Array[Int]): Array[Long] = {
  val len = bits.length
  val memo = mutable.HashMap.empty[(Int, Boolean), Array[Long]]

  def dp(i: Int, tight: Boolean): Array[Long] = {
    if (i == len) {
      val arr = new Array[Long](len + 1)
      arr(0) = 1
      arr
    } else {
      memo.getOrElseUpdate((i, tight), {
        val maxDigit = if (tight) bits(i) else 1
        val arr = new Array[Long](len + 1)
        for (d <- 0 to maxDigit) {
          val newTight = tight && (d == bits(i))
          val nextArr = dp(i + 1, newTight)
          val bitValue = if (d == 1) 1 else 0
          for (j <- 0 to (len - bitValue)) {
            arr(j + bitValue) += nextArr(j)
          }
        }
        arr
      })
    }
  }

  dp(0, tight = true)
}
```

