import scala.collection.mutable

def solve(n: Long, k: Long): Long = {
  if (k == 0) {
    if (n >= 1) 1L else 0L
  } else {
    val MAX = 60
    val T = new Array[Int](MAX + 1)
    T(1) = 0
    for (i <- 2 to MAX) {
      T(i) = 1 + T(Integer.bitCount(i))
    }
    val setS = (1 to MAX).filter(i => T(i) == k - 1).toSet
    val total = countNumbers(n, setS)
    if (k == 1) total - 1L else total
  }
}

def countNumbers(n: Long, setS: Set[Int]): Long = {
  if (n == 0) 0L
  else {
    val s = n.toBinaryString
    val len = s.length
    val memo = mutable.Map[(Int, Int, Int), Long]()

    def dfs(pos: Int, tight: Boolean, count: Int): Long = {
      if (pos == len) {
        if (setS.contains(count)) 1L else 0L
      } else {
        val key = (pos, if (tight) 1 else 0, count)
        if (memo.contains(key)) memo(key)
        else {
          val limit = if (tight) s(pos) - '0' else 1
          var res = 0L
          for (d <- 0 to limit) {
            val newTight = tight && (d == limit)
            val newCount = if (d == 1) count + 1 else count
            res += dfs(pos + 1, newTight, newCount)
          }
          memo.put(key, res)
          res
        }
      }
    }

    dfs(0, true, 0)
  }
}
```

